import React, { useState, useEffect } from 'react';
import api from './api';
import BudgetForm from './components/BudgetForm';
import InvestmentForm from './components/InvestmentForm';
import AnalyticsDashboard from './components/AnalyticsDashboard';
import TransactionList from './components/TransactionList';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [view, setView] = useState('dashboard');
  const [authView, setAuthView] = useState('login');
  const [transactions, setTransactions] = useState([]);
  const [budgets, setBudgets] = useState([]);
  const [investments, setInvestments] = useState([]);

  const login = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/login', { 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      setToken(res.data.token);
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      setView('dashboard');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const register = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post('/auth/register', { 
        name: e.target.name.value, 
        email: e.target.email.value, 
        password: e.target.password.value 
      });
      alert('Registered successfully! Please login with your credentials.');
      setAuthView('login');
    } catch (err) {
      alert(err.response?.data?.error || err.message);
    }
  };

  const logout = () => {
    setToken(null);
    setUser(null);
    localStorage.removeItem('token');
    setView('dashboard');
  };

  const loadTransactions = async () => {
    try {
      const res = await api.get('/transactions');
      setTransactions(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadBudgets = async () => {
    try {
      const res = await api.get('/budgets');
      setBudgets(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const loadInvestments = async () => {
    try {
      const res = await api.get('/investments');
      setInvestments(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (token) {
      loadTransactions();
      loadBudgets();
      loadInvestments();
    }
  }, [token]);

  // Login Page (default)
  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-purple-900 to-pink-800 flex items-center justify-center p-4 relative overflow-hidden">
        {/* Background decoration */}
        <div className="absolute inset-0">
          <div className="absolute -top-40 -right-40 w-80 h-80 bg-purple-300/20 rounded-full blur-3xl animate-pulse"></div>
          <div className="absolute -bottom-40 -left-40 w-80 h-80 bg-indigo-300/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        </div>

        <div className="bg-white/95 backdrop-blur-xl rounded-3xl shadow-2xl p-12 max-w-md w-full border border-white/30 relative z-10 max-h-[90vh] overflow-y-auto">
          {/* Logo */}
          <div className="text-center mb-12">
            <div className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl shadow-lg mb-6 mx-auto">
              <svg className="w-8 h-8 text-white mr-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
              </svg>
              <span className="text-xl font-bold text-white">FinTrack</span>
            </div>
            {authView === 'login' ? (
              <>
                <h1 className="text-4xl font-black bg-gradient-to-r from-gray-800 to-gray-700 bg-clip-text text-transparent mb-3">Welcome Back</h1>
                <p className="text-gray-600 text-xl font-medium">Sign in to continue managing your finances</p>
              </>
            ) : (
              <>
                <h1 className="text-4xl font-black bg-gradient-to-r from-emerald-700 to-teal-700 bg-clip-text text-transparent mb-3">Join FinTrack</h1>
                <p className="text-gray-600 text-xl font-medium">Create your free account in seconds</p>
              </>
            )}
          </div>

          {authView === 'login' ? (
            <>
              <h2 className="text-2xl font-black text-gray-900 mb-6 text-center">Welcome Back</h2>
              <form onSubmit={login} className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Email Address</label>
                  <input 
                    name="email" 
                    type="email" 
                    placeholder="your@email.com" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/30 focus:border-indigo-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Password</label>
                  <input 
                    name="password" 
                    type="password" 
                    placeholder="••••••••" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/30 focus:border-indigo-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <button 
                  type="submit" 
                  className="w-full bg-gradient-to-r from-indigo-600 via-purple-600 to-pink-600 text-white py-6 px-8 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-indigo-700 hover:via-purple-700 hover:to-pink-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300 flex items-center justify-center space-x-2"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 16l-4-4m0 0l4-4m-4 4h14m-5 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" />
                  </svg>
                  <span>Sign In</span>
                </button>
              </form>
            </>
          ) : (
            <>
              <h2 className="text-2xl font-black text-gray-900 mb-6 text-center">Create Free Account</h2>
              <form onSubmit={register} className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Full Name</label>
                  <input 
                    name="name" 
                    type="text" 
                    placeholder="John Doe" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Email Address</label>
                  <input 
                    name="email" 
                    type="email" 
                    placeholder="your@email.com" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    required 
                  />
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3 tracking-wide">Password</label>
                  <input 
                    name="password" 
                    type="password" 
                    placeholder="••••••••" 
                    className="w-full px-6 py-5 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white/50 backdrop-blur-sm text-lg placeholder-gray-500 shadow-inner hover:shadow-md transition-all duration-300" 
                    minLength="6"
                    required 
                  />
                </div>
                <button 
                  type="submit" 
                  className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 text-white py-6 px-8 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-emerald-600 hover:to-teal-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300 flex items-center justify-center space-x-2"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" />
                  </svg>
                  <span>Create Account</span>
                </button>
              </form>
            </>
          )}

          {/* Sign up button at bottom */}
          <div className="mt-10 pt-10 border-t-2 border-indigo-100">
            <div className="text-center">
              <p className="text-lg font-semibold text-gray-600 mb-6">Don't have an account?</p>
{authView === 'login' ? (
                <button 
                  type="button"
                  onClick={() => setAuthView('register')}
                  className="w-full bg-gradient-to-r from-emerald-500 to-teal-600 text-white py-5 px-8 rounded-2xl font-bold text-xl shadow-2xl hover:shadow-3xl hover:from-emerald-600 hover:to-teal-700 transform hover:scale-[1.02] hover:-translate-y-1 transition-all duration-300 flex items-center justify-center space-x-3 group"
                >
                  <svg className="w-6 h-6 group-hover:rotate-12 transition-transform duration-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" />
                  </svg>
                  <span>Create Free Account</span>
                </button>
              ) : (
                <button 
                  type="button"
                  onClick={() => setAuthView('login')}
                  className="w-full bg-gradient-to-r from-gray-500 to-gray-600 text-white py-5 px-8 rounded-2xl font-bold text-xl shadow-lg hover:shadow-xl hover:bg-gray-600 transition-all duration-300 flex items-center justify-center space-x-3"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 16l-4-4m0 0l4-4m-4 4h14m-5 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" />
                  </svg>
                  <span>Back to Sign In</span>
                </button>
              )}
              <p className="text-xs text-gray-500 mt-4 opacity-75">No credit card required • Cancel anytime</p>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const refreshAll = () => {
    loadTransactions();
    loadBudgets();
    loadInvestments();
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 via-blue-50 to-indigo-100">
      {/* Navigation - same as before */}
      <nav className="bg-white shadow-lg border-b border-gray-200/50 backdrop-blur-md">
        <div className="max-w-7xl mx-auto px-6 py-5 flex justify-between items-center">
          <div className="flex items-center space-x-4">
            <h1 className="text-3xl font-black bg-gradient-to-r from-indigo-600 to-purple-600 bg-clip-text text-transparent">
              FinTrack
            </h1>
            <span className="text-sm text-gray-600 font-semibold bg-indigo-100 text-indigo-700 px-4 py-1 rounded-full">Welcome, {user?.name}</span>
          </div>
          <div className="flex items-center space-x-2">
            {['dashboard', 'transactions', 'budgets', 'investments', 'analytics'].map((v) => (
              <button
                key={v}
                onClick={() => setView(v)}
                className={`px-6 py-3 rounded-2xl font-semibold text-sm transition-all duration-300 ${
                  view === v 
                    ? 'bg-gradient-to-r from-indigo-500 to-purple-600 text-white shadow-lg hover:shadow-xl transform -translate-y-0.5' 
                    : 'text-gray-600 hover:text-indigo-600 hover:bg-indigo-50 border border-gray-200 hover:border-indigo-300'
                }`}
              >
                {v.charAt(0).toUpperCase() + v.slice(1)}
              </button>
            ))}
            <button onClick={logout} className="bg-gradient-to-r from-red-500 to-rose-600 text-white px-8 py-3 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
              Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-12">
        <div className="mb-12 flex justify-between items-center">
          <h2 className="text-4xl font-black text-gray-900 capitalize">{view}</h2>
          <button onClick={refreshAll} className="bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-600 hover:to-teal-700 text-white px-8 py-4 rounded-2xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-300">
            Refresh Data
          </button>
        </div>

        {/* Dashboard content - keep existing */}
        {view === 'dashboard' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <AnalyticsDashboard />
            <div className="space-y-8">
              <div className="bg-white rounded-3xl shadow-2xl p-10">
                <h3 className="text-3xl font-black text-gray-900 mb-6">Quick Stats</h3>
                <div className="grid grid-cols-3 gap-6">
                  <div className="text-center p-6 bg-gradient-to-b from-green-50 to-green-100 rounded-2xl">
                    <p className="text-4xl font-black text-green-600">${transactions.reduce((sum, t) => sum + (t.type === 'income' ? t.amount : 0), 0).toLocaleString()}</p>
                    <p className="text-lg font-semibold text-green-800">Total Income</p>
                  </div>
                  <div className="text-center p-6 bg-gradient-to-b from-red-50 to-red-100 rounded-2xl">
                    <p className="text-4xl font-black text-red-600">-${transactions.reduce((sum, t) => sum + (t.type === 'expense' ? t.amount : 0), 0).toLocaleString()}</p>
                    <p className="text-lg font-semibold text-red-800">Total Expenses</p>
                  </div>
                  <div className="text-center p-6 bg-gradient-to-b from-blue-50 to-blue-100 rounded-2xl">
                    <p className="text-4xl font-black text-blue-600">${budgets.reduce((sum, b) => sum + b["limit"], 0).toLocaleString()}</p>
                    <p className="text-lg font-semibold text-blue-800">Monthly Budget</p>
                  </div>
                </div>
              </div>
              <div className="bg-white rounded-3xl shadow-2xl p-10">
                <h3 className="text-3xl font-black text-gray-900 mb-6">Recent Investments</h3>
                <div className="space-y-4">
                  {investments.slice(0, 3).map((inv) => (
                    <div key={inv.id} className="flex justify-between items-center p-6 bg-gradient-to-r from-indigo-50 to-purple-50 rounded-xl border-l-4 border-indigo-500">
                      <div>
                        <p className="text-xl font-bold">${inv.principal.toLocaleString()}</p>
                        <p className="text-sm text-gray-600">Rate: {inv.rate}% | {inv.duration}yrs</p>
                      </div>
                      <div className="text-right">
                        <p className="text-2xl font-black text-green-600">${inv.current_value.toLocaleString()}</p>
                        <p className="text-green-600 font-semibold">+{(inv.current_value - inv.principal).toLocaleString()}</p>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {view === 'transactions' && (
          <div className="space-y-8">
            <div className="bg-white rounded-3xl shadow-2xl p-8">
              <h3 className="text-3xl font-black text-gray-900 mb-8">Add Transaction</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <input type="number" placeholder="Amount" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-500/30" />
<select name="type" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-500/30">
                  <option value="">Select Type</option>
                  <option value="income">Income</option>
                  <option value="expense">Expense</option>
                </select>
<select name="category" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-500/30">
                  <option value="">Select Category</option>
                  <option value="salary">Salary</option>
                  <option value="freelance">Freelance</option>
                  <option value="investment">Investment</option>
                  <option value="grocery">Grocery</option>
                  <option value="food">Food</option>
                  <option value="rent">Rent</option>
                  <option value="utilities">Utilities</option>
                  <option value="transport">Transport</option>
                  <option value="entertainment">Entertainment</option>
                  <option value="other">Other</option>
                </select>
                <input type="date" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-blue-500/30" />
                <button className="md:col-span-2 lg:col-span-1 bg-gradient-to-r from-blue-500 to-indigo-600 text-white p-6 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-blue-600 hover:to-indigo-700 transform hover:scale-[1.02] transition-all duration-300">
                  Add Transaction
                </button>
              </div>
            </div>
            <div className="bg-white rounded-3xl shadow-2xl overflow-hidden">
              <div className="p-8 bg-gradient-to-r from-blue-500 to-indigo-600 text-white">
                <h3 className="text-3xl font-black">Transactions</h3>
              </div>
              <div className="divide-y divide-gray-200">
                {transactions.map((t) => (
                  <div key={t.id} className="p-8 hover:bg-gray-50 transition-colors flex justify-between items-center">
                    <div className="flex items-center space-x-6">
                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-xl ${t.type === 'income' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                        {t.type === 'income' ? '+' : '-'}${t.amount.toLocaleString()}
                      </div>
                      <div>
                        <p className="text-xl font-bold text-gray-900 capitalize">{t.category}</p>
                        <p className="text-sm text-gray-500">{new Date(t.date).toLocaleDateString()}</p>
                      </div>
                    </div>
                    <div className="flex items-center space-x-4">
                      <span className={`px-4 py-2 rounded-full text-sm font-bold ${
                        t.type === 'income' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                      }`}>
                        {t.type.toUpperCase()}
                      </span>
                      <button className="bg-red-500 hover:bg-red-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-200">
                        Delete
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {view === 'budgets' && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-white rounded-3xl shadow-2xl p-10">
              <h3 className="text-3xl font-black text-gray-900 mb-8">Monthly Budget</h3>
              <div className="space-y-6">
                {budgets.map((b) => (
                  <div key={b.id} className="bg-gradient-to-r from-yellow-50 to-orange-50 p-8 rounded-2xl border-4 border-yellow-200">
                    <div className="flex justify-between items-start mb-4">
                      <h4 className="text-2xl font-bold text-gray-900">{new Date(b.month).toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}</h4>
                      <span className="text-3xl font-black text-orange-600">${b["limit"].toLocaleString()}</span>
                    </div>
                    <div className="w-full bg-gray-200 rounded-full h-4">
                      <div className="bg-gradient-to-r from-orange-400 to-red-500 h-4 rounded-full" style={{width: '65%'}}></div>
                    </div>
                    <p className="text-sm text-gray-600 mt-2">65% used ($1,625 / $2,500)</p>
                  </div>
                ))}
              </div>
            </div>
            <div className="bg-white rounded-3xl shadow-2xl p-10">
              <h3 className="text-3xl font-black text-gray-900 mb-8">Add Budget</h3>
              <div className="space-y-6">
                <input type="month" className="w-full p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-green-500/30" />
                <input type="number" placeholder="Budget Amount" className="w-full p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-green-500/30" />
                <button className="w-full bg-gradient-to-r from-green-500 to-emerald-600 text-white p-6 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-green-600 hover:to-emerald-700 transform hover:scale-[1.02] transition-all duration-300">
                  Set Budget
                </button>
              </div>
            </div>
          </div>
        )}

        {view === 'investments' && (
          <div className="space-y-8">
            <div className="bg-white rounded-3xl shadow-2xl p-8">
              <h3 className="text-3xl font-black text-gray-900 mb-8">Add Investment</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input type="number" placeholder="Principal" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-purple-500/30" />
                <input type="number" step="0.1" placeholder="Rate %" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-purple-500/30" />
                <input type="number" placeholder="Years" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-purple-500/30" />
                <input type="number" placeholder="Current Value" className="p-6 border-2 border-gray-200 rounded-2xl focus:ring-4 focus:ring-purple-500/30" />
                <button className="md:col-span-2 bg-gradient-to-r from-purple-500 to-pink-600 text-white p-6 rounded-2xl font-black text-xl shadow-2xl hover:shadow-3xl hover:from-purple-600 hover:to-pink-700 transform hover:scale-[1.02] transition-all duration-300">
                  Add Investment
                </button>
              </div>
            </div>
            <div className="bg-white rounded-3xl shadow-2xl p-10">
              <h3 className="text-3xl font-black text-gray-900 mb-8">Portfolio</h3>
              <div className="space-y-6">
                {investments.map((inv) => (
                  <div key={inv.id} className="flex justify-between items-center p-8 bg-gradient-to-r from-purple-50 to-pink-50 rounded-3xl border border-purple-200">
                    <div>
                      <p className="text-2xl font-bold">${inv.principal.toLocaleString()}</p>
                      <p className="text-sm text-gray-600">Rate: {inv.rate}% | {inv.duration} years</p>
                    </div>
                    <div className="text-right">
                      <p className="text-3xl font-black text-green-600">${inv.current_value.toLocaleString()}</p>
                      <p className="text-green-600 font-semibold">+${(inv.current_value - inv.principal).toLocaleString()}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {view === 'analytics' && <AnalyticsDashboard />}
      </main>
    </div>
  );
}

export default App;
